mapper.select:
SELECT id, type_id, item_name, deduct_mode, fixed_score, base_score, per_person_score, range_config, description, sort_order, status, allow_photo, allow_remark, allow_students, created_at, updated_at FROM deduction_items WHERE deleted = 0
AND type_id = #{typeId}
ORDER BY type_id, sort_order ASC, created_at DESC
